const input = $input.first().json;
const query = input.query || {};
const { startDate, endDate } = query;

const start = startDate || '2026-01-01';
const end = endDate || '2026-04-23';

const queryNuevos = `WITH semanas AS (
  SELECT generate_series(
    DATE_TRUNC('week', '${start}'::date),
    DATE_TRUNC('week', '${end}'::date),
    '1 week'::interval
  )::date as semana_inicio
)
SELECT 
  TO_CHAR(s.semana_inicio, 'YYYY-WW') as semana,
  COUNT(a.id)::integer as nuevos
FROM semanas s
LEFT JOIN alumnos a ON DATE_TRUNC('week', a.fecha_registro) = s.semana_inicio
GROUP BY s.semana_inicio
ORDER BY s.semana_inicio ASC;`;

const queryConversion = `WITH semanas AS (
  SELECT generate_series(
    DATE_TRUNC('week', '${start}'::date),
    DATE_TRUNC('week', '${end}'::date),
    '1 week'::interval
  )::date as semana_inicio
)
SELECT 
  TO_CHAR(s.semana_inicio, 'YYYY-WW') as semana,
  ROUND(100.0 * COUNT(CASE WHEN a.estado IN ('REGISTRADO', 'ACTIVO') THEN 1 END) / 
    NULLIF(COUNT(a.id), 0), 1)::integer as conversion
FROM semanas s
LEFT JOIN alumnos a ON DATE_TRUNC('week', a.fecha_registro) = s.semana_inicio
GROUP BY s.semana_inicio
ORDER BY s.semana_inicio ASC;`;

const queryIngresos = `SELECT 
  TO_CHAR(DATE_TRUNC('month', p.fecha_pago), 'YYYY-MM') as mes,
  COALESCE(SUM(p.monto), 0)::decimal as ingresos
FROM pagos_manuales p
WHERE p.fecha_pago BETWEEN '${start}'::date AND '${end}'::date
GROUP BY DATE_TRUNC('month', p.fecha_pago)
ORDER BY mes ASC;`;

return [{
  json: {
    queryNuevos,
    queryConversion,
    queryIngresos
  }
}];

const nuevos = $('nuevos').all().map(row => row.json);
const conversion = $('conversion').all().map(row => row.json);
const ingresos = $('ingresos').all().map(row => row.json);

return [{
  json: {
    items: {
      nuevos_por_semana: nuevos,
      conversion_por_semana: conversion,
      ingresos_acumulados: ingresos
    }
  }
}];

